import {
  Box,
  Heading,
  Text,
} from "@chakra-ui/react";
import React from "react";
import Slider from "react-slick";
import { Image } from "@chakra-ui/react";

import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";

const UserSlider = () => {
  const slides = [
    {
      img: "https://images.pexels.com/photos/5212653/pexels-photo-5212653.jpeg",
      title: "Learn Without Limits",
      desc: "Join thousands of learners and gain new skills every day.",
    },
    {
      img: "https://www.mit.edu/files/images/201807/15656704711_00457bd2c9_b_1.jpg",
      title: "Top Universities & Courses",
      desc: "Access high-quality courses from top institutions.",
    },
    {
      img: "https://inup.iitkgp.ac.in/images/iit_kgp.jpg",
      title: "Build Real Skills",
      desc: "Learn practical skills that matter in real life.",
    },
    {
      img: "https://www.vedantu.com/seo/content-images/33e42c38-8332-4d51-9dcf-65a4f262b5da.png",
      title: "Upgrade Your Career",
      desc: "Take the next step in your professional journey.",
    },
  ];
  const NextArrow = ({ onClick }) => (
  <Box
    position="absolute"
    right="10px"
    top="55%"
    transform="translateY(-50%)"
    zIndex="2"
    bg="white"
    borderRadius="50%"
    w="40px"
    h="40px"
    display="flex"
    alignItems="center"
    justifyContent="center"
    cursor="pointer"
    boxShadow="md"
    onClick={onClick}
  >
   {">"}
  </Box>
);

const PrevArrow = ({ onClick }) => (
  <Box
    position="absolute"
    left="10px"
    top="55%"
    transform="translateY(-50%)"
    zIndex="2"
    bg="white"
    borderRadius="50%"
    w="40px"
    h="40px"
    display="flex"
    alignItems="center"
    justifyContent="center"
    cursor="pointer"
    boxShadow="md"
    onClick={onClick}
  >
   {"<"}
  </Box>
);
  const settings = {
    dots: true,
    infinite: true,
    speed: 1000,
    slidesToShow: 1,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 4000,
    nextArrow: <NextArrow />,
    prevArrow: <PrevArrow />,
  };

  return (
    <Box w="100%" overflow="hidden">
      <Slider {...settings}>
        {slides.map((slide, index) => (
          <Box key={index} position="relative">
            
            {/* Image */}
            <Image
              src={slide.img}
              w="100%"
              h={{ base: "250px", md: "400px" }}
              objectFit="cover"
            />

            {/* Overlay */}
            <Box
              position="absolute"
              top="0"
              left="0"
              w="100%"
              h="100%"
              bg="rgba(0,0,0,0.4)"
            />

            {/* Content */}
            <Box
              position="absolute"
              top="50%"
              left="50%"
              transform="translate(-50%, -50%)"
              color="white"
              textAlign="center"
              px={4}
            >
              <Heading fontSize={{ base: "2xl", md: "4xl" }}>
                {slide.title}
              </Heading>
              <Text mt={2}>{slide.desc}</Text>
            </Box>

          </Box>
        ))}
      </Slider>
    </Box>
  );
};

export default UserSlider;
